import scala.util.matching.Regex

def solve(code: Array[String], businessLine: Array[String], isActive: Array[Boolean]): Array[String] = {
    val businessOrder = Map("electronics" -> 0, "grocery" -> 1, "pharmacy" -> 2, "restaurant" -> 3)
    val pattern: Regex = "^[a-zA-Z0-9_]+$".r

    val validCoupons = for {
        i <- code.indices
        if code(i).nonEmpty && pattern.matches(code(i))
        if businessOrder.contains(businessLine(i))
        if isActive(i)
    } yield (businessOrder(businessLine(i)), code(i))

    validCoupons.sortBy { case (order, code) => (order, code) }.map(_._2).toArray
}
